namespace sv_14073df30c3c4b7bb4fcf7b4aa1b587f.Services;

public class SettingsService : ISettingsService
{
    private UserProfile _profile = new("John Doe", "john@example.com", "https://via.placeholder.com/100", "Software developer and tech enthusiast.");
    private NotificationPrefs _notificationPrefs = new(true, false, true, new List<string> { "marketing" });
    private SecuritySettings _securitySettings = new(false, DateTime.UtcNow.AddDays(-30), new List<ActiveSession>
    {
        new("session-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("session-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
        new("session-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-1))
    });
    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() => Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() => Task.FromResult(_notificationPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() => Task.FromResult(_securitySettings);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _securitySettings = _securitySettings with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        var updated = _securitySettings.Sessions.Where(s => s.Id != sessionId).ToList();
        _securitySettings = _securitySettings with { Sessions = updated };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() => Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

