}

/* Channels list */
.channels-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.75rem;
    background: #f8fafc;
    border-radius: 6px;
    border: 1px solid #e2e8f0;
    max-width: 480px;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
    cursor: pointer;
}

.channel-item:hover {
    background: #e2e8f0;
}

/* Expandable panel */
.expandable-panel {
    border: 1px solid #e2e8f0;
    border-radius: 8px;
