}

.panel-header:hover {
    background: #f1f5f9;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #e2e8f0;
}

/* Status indicator */
.status-indicator {
    font-size: 0.8rem;
    padding: 0.25rem 0.6rem;
    border-radius: 12px;
    font-weight: 600;
}

.status-indicator.enabled {
    background: #dcfce7;
    color: #166534;
}

.status-indicator.disabled {
    background: #fee2e2;
    color: #991b1b;
}

/* Sessions table */
.sessions-table-container {
    overflow-x: auto;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem 1rem;
    text-align: left;
    border-bottom: 1px solid #e2e8f0;
}

.sessions-table th {
    background: #f8fafc;
    font-weight: 600;
    color: #475569;
}

.sessions-table tr:hover {
    background: #f8fafc;
}

.current-badge {
    font-size: 0.8rem;
    padding: 0.2rem 0.5rem;
    background: #dbeafe;
    color: #1e40af;
    border-radius: 4px;
    font-weight: 500;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal {
    background: white;
    padding: 2rem;
    border-radius: 12px;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
}

.modal h3 {
    margin: 0 0 1rem;
}

.modal p {
    color: #475569;
    margin-bottom: 1.5rem;
}

/* Radio group */
.radio-group {
    display: flex;
    gap: 1.5rem;
}

.radio-label {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
    font-weight: 400;
}

/* Live preview */
.live-preview {
    border: 1px solid #e2e8f0;
    border-radius: 8px;
    overflow: hidden;
    max-width: 480px;
    margin-bottom: 1.5rem;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    font-weight: 600;
    border-bottom: 1px solid #e2e8f0;
}

.preview-body {
    padding: 1rem;
}

.preview-body p {
    margin: 0.25rem 0;
}

.preview-btn {
    margin-top: 0.75rem;
    padding: 0.4rem 1rem;
    border-radius: 4px;
    border: none;
    cursor: pointer;
    font-weight: 500;
}

/* Preview theme variants */
.preview-light {
    background: #ffffff;
    color: #1e293b;
}

.preview-light .preview-header {
    background: #f8fafc;
}

.preview-light .preview-btn {
    background: #0369a1;
    color: white;
}

.preview-dark {
    background: #1e293b;
    color: #e2e8f0;
}

.preview-dark .preview-header {
    background: #0f172a;
    border-color: #334155;
}

.preview-dark .preview-body {
    border-color: #334155;
}

.preview-dark .preview-btn {
    background: #38bdf8;
    color: #0f172a;
}

.preview-system {
    background: #f1f5f9;
    color: #334155;
}

.preview-system .preview-header {
    background: #e2e8f0;
}

.preview-system .preview-btn {
    background: #6366f1;
    color: white;
}

/* Preview font sizes */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 0.95rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

/* Preview compact */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

/* Toast */
.toast {
    position: sticky;
    top: 0;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-weight: 500;
    font-size: 0.9rem;
    animation: slideDown 0.2s ease;
}

.toast.success {
    background: #dcfce7;
    color: #166534;
    border: 1px solid #bbf7d0;
}

.toast.error {
    background: #fee2e2;
    color: #991b1b;
    border: 1px solid #fecaca;
}

.toast.info {
    background: #dbeafe;
    color: #1e40af;
    border: 1px solid #bfdbfe;
}

.toast-close {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    color: inherit;
    opacity: 0.7;
}

.toast-close:hover {
    opacity: 1;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

