    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _editTwoFactor;
    private string _currentSessionId = "session-1";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private AppearanceSettings? _appearance;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
        await LoadNotifications();
        await LoadSecurity();
        await LoadAppearance();
    }

    private void SetSection(string section)
    {
        ActiveSection = section;
        DismissToast();
    }

    // Profile methods
    private async Task LoadProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
        ResetProfileEdit();
    }

    private void ResetProfileEdit()
    {
        if (_profile == null) return;
        _editProfile = new ProfileEdit
        {
            DisplayName = _profile.DisplayName,
            Email = _profile.Email,
            AvatarUrl = _profile.AvatarUrl,
            Bio = _profile.Bio
        };
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editProfile.DisplayName, _editProfile.Email, _editProfile.AvatarUrl, _editProfile.Bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileEdit();
        ShowToast("Changes discarded.", "info");
    }

    // Notification methods
    private async Task LoadNotifications()
    {
        _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
        _editEmailNotifications = _notificationPrefs.EmailNotifications;
        _editPushNotifications = _notificationPrefs.PushNotifications;
        _editWeeklyDigest = _notificationPrefs.WeeklyDigest;
        _editMutedChannels = new List<string>(_notificationPrefs.MutedChannels);
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_editMutedChannels.Contains(channel))
            _editMutedChannels.Add(channel);
        else if (!muted)
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, new List<string>(_editMutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
        ShowToast("Notification preferences saved!", "success");
    }

    // Security methods
    private async Task LoadSecurity()
    {
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _editTwoFactor = _securitySettings.TwoFactorEnabled;
    }

    private void TogglePasswordPanel() => _showPasswordPanel = !_showPasswordPanel;

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _showPasswordPanel = false;
        await LoadSecurity();
        ShowToast("Password updated successfully!", "success");
    }

    private void ConfirmRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
        _showRevokeConfirm = false;
    }

    private async Task RevokeSession()
    {
        if (_sessionToRevoke != null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadSecurity();
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.", "success");
        }
        CancelRevoke();
    }

    private string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }

    // Appearance methods
    private async Task LoadAppearance()
    {
        _appearance = await SettingsService.GetAppearanceAsync();
        _editTheme = _appearance.Theme;
        _editFontSize = _appearance.FontSize;
        _editLanguage = _appearance.Language;
        _editCompactMode = _appearance.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-{_editTheme.ToLower()} preview-font-{_editFontSize.ToLower()}";
        if (_editCompactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast
    private void ShowToast(string message, string type)
    {
        ToastMessage = message;
        ToastType = type;
    }

    private void DismissToast() => ToastMessage = null;

    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";
    }
}
