.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

/* Toast */
.toast {
    position: sticky;
    top: 0;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-weight: 500;
    font-size: 0.9rem;
    animation: slideDown 0.2s ease;
}

.toast.success {
    background: #dcfce7;
    color: #166534;
    border: 1px solid #bbf7d0;
}

.toast.error {
    background: #fee2e2;
    color: #991b1b;
    border: 1px solid #fecaca;
}

.toast.info {
    background: #dbeafe;
    color: #1e40af;
    border: 1px solid #bfdbfe;
}

.toast-close {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    color: inherit;
    opacity: 0.7;
}

.toast-close:hover {
    opacity: 1;
}

@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}
