+}
+
+/* Toggle switches */
+.toggle-group {
+    margin-bottom: 1rem;
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+}
+
+.toggle-label {
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+    cursor: pointer;
+    font-weight: 500;
+    color: #374151;
+}
+
+.toggle-label input[type="checkbox"] {
+    width: 40px;
+    height: 22px;
+    appearance: none;
+    background: #cbd5e1;
+    border-radius: 11px;
+    position: relative;
+    cursor: pointer;
+    transition: background 0.2s;
+    flex-shrink: 0;
+}
+
+.toggle-label input[type="checkbox"]::after {
+    content: '';
+    position: absolute;
+    width: 18px;
+    height: 18px;
+    border-radius: 50%;
+    background: white;
+    top: 2px;
+    left: 2px;
+    transition: transform 0.2s;
+}
+
+.toggle-label input[type="checkbox"]:checked {
+    background: #0369a1;
+}
+
+.toggle-label input[type="checkbox"]:checked::after {
+    transform: translateX(18px);
+}
+
+/* Channels list */
+.channels-list {
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+    padding: 0.75rem;
+    background: #f8fafc;
+    border-radius: 6px;
+    border: 1px solid #e2e8f0;
+    max-width: 480px;
+}
+
+.channel-item {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    padding: 0.4rem 0.5rem;
+    border-radius: 4px;
+    cursor: pointer;
+}
+
+.channel-item:hover {
+    background: #e2e8f0;
+}
+
+/* Expandable panel */
+.expandable-panel {
+    border: 1px solid #e2e8f0;
+    border-radius: 8px;
+    margin-bottom: 1.5rem;
+    overflow: hidden;
+}
+
+.panel-header {
+    width: 100%;
+    padding: 1rem 1.25rem;
+    background: #f8fafc;
+    border: none;
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    cursor: pointer;
+    font-weight: 600;
+    color: #1e293b;
+    font-size: 0.95rem;
+}
+
+.panel-header:hover {
+    background: #f1f5f9;
+}
+
+.panel-body {
+    padding: 1.25rem;
+    border-top: 1px solid #e2e8f0;
+}
+
+/* Status indicator */
+.status-indicator {
+    font-size: 0.8rem;
+    padding: 0.25rem 0.6rem;
+    border-radius: 12px;
+    font-weight: 600;
+}
+
+.status-indicator.enabled {
+    background: #dcfce7;
+    color: #166534;
+}
+
+.status-indicator.disabled {
+    background: #fee2e2;
+    color: #991b1b;
+}
+
+/* Sessions table */
+.sessions-table-container {
+    overflow-x: auto;
+}
+
+.sessions-table {
+    width: 100%;
+    border-collapse: collapse;
+    font-size: 0.9rem;
+}
+
+.sessions-table th,
+.sessions-table td {
+    padding: 0.75rem 1rem;
+    text-align: left;
+    border-bottom: 1px solid #e2e8f0;
+}
+
+.sessions-table th {
+    background: #f8fafc;
+    font-weight: 600;
+    color: #475569;
+}
+
+.sessions-table tr:hover {
+    background: #f8fafc;
+}
+
+.current-badge {
+    font-size: 0.8rem;
+    padding: 0.2rem 0.5rem;
+    background: #dbeafe;
+    color: #1e40af;
+    border-radius: 4px;
+    font-weight: 500;
+}
+
+/* Modal */
+.modal-overlay {
+    position: fixed;
+    top: 0;
+    left: 0;
+    width: 100%;
+    height: 100%;
+    background: rgba(0, 0, 0, 0.5);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1000;
+}
+
+.modal {
+    background: white;
+    padding: 2rem;
+    border-radius: 12px;
+    max-width: 420px;
+    width: 90%;
+    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
+}
+
+.modal h3 {
+    margin: 0 0 1rem;
+}
+
+.modal p {
+    color: #475569;
+    margin-bottom: 1.5rem;
+}
+
+/* Radio group */
+.radio-group {
+    display: flex;
+    gap: 1.5rem;
+}
+
+.radio-label {
+    display: flex;
+    align-items: center;
+    gap: 0.4rem;
+    cursor: pointer;
+    font-weight: 400;
+}
+
+/* Live preview */
+.live-preview {
+    border: 1px solid #e2e8f0;
+    border-radius: 8px;
+    overflow: hidden;
+    max-width: 480px;
+    margin-bottom: 1.5rem;
+    transition: all 0.2s ease;
+}
+
+.preview-header {
+    padding: 0.75rem 1rem;
+    font-weight: 600;
+    border-bottom: 1px solid #e2e8f0;
+}
+
+.preview-body {
+    padding: 1rem;
+}
+
+.preview-body p {
+    margin: 0.25rem 0;
+}
+
+.preview-btn {
+    margin-top: 0.75rem;
+    padding: 0.4rem 1rem;
+    border-radius: 4px;
+    border: none;
+    cursor: pointer;
+    font-weight: 500;
+}
+
+/* Preview theme variants */
+.preview-light {
+    background: #ffffff;
+    color: #1e293b;
+}
+
+.preview-light .preview-header {
+    background: #f8fafc;
+}
+
+.preview-light .preview-btn {
+    background: #0369a1;
+    color: white;
+}
+
+.preview-dark {
+    background: #1e293b;
+    color: #e2e8f0;
+}
+
+.preview-dark .preview-header {
+    background: #0f172a;
+    border-color: #334155;
+}
+
+.preview-dark .preview-body {
+    border-color: #334155;
+}
+
+.preview-dark .preview-btn {
+    background: #38bdf8;
+    color: #0f172a;
+}
+
+.preview-system {
+    background: #f1f5f9;
+    color: #334155;
+}
+
+.preview-system .preview-header {
+    background: #e2e8f0;
+}
+
+.preview-system .preview-btn {
+    background: #6366f1;
+    color: white;
+}
+
+/* Preview font sizes */
+.preview-font-small {
+    font-size: 0.8rem;
+}
+
+.preview-font-medium {
+    font-size: 0.95rem;
+}
+
+.preview-font-large {
+    font-size: 1.15rem;
+}
+
+/* Preview compact */
+.preview-compact .preview-header {
+    padding: 0.4rem 0.75rem;
+}
+
+.preview-compact .preview-body {
+    padding: 0.5rem 0.75rem;
+}
+
+/* Toast */
+.toast {
+    position: sticky;
+    top: 0;
+    padding: 0.75rem 1rem;
+    border-radius: 6px;
+    margin-bottom: 1.5rem;
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    font-weight: 500;
+    font-size: 0.9rem;
+    animation: slideDown 0.2s ease;
+}
+
+.toast.success {
+    background: #dcfce7;
+    color: #166534;
+    border: 1px solid #bbf7d0;
+}
+
+.toast.error {
+    background: #fee2e2;
+    color: #991b1b;
+    border: 1px solid #fecaca;
+}
+
+.toast.info {
+    background: #dbeafe;
+    color: #1e40af;
+    border: 1px solid #bfdbfe;
+}
+
+.toast-close {
+    background: none;
+    border: none;
+    cursor: pointer;
+    font-size: 1rem;
+    color: inherit;
+    opacity: 0.7;
+}
+
+.toast-close:hover {
+    opacity: 1;
+}
+
+@keyframes slideDown {
+    from {
+        opacity: 0;
+        transform: translateY(-10px);
+    }
+    to {
+        opacity: 1;
+        transform: translateY(0);
+    }
+}
+

toolArgs.file_text:
@page "/settings"
@using sv_14073df30c3c4b7bb4fcf7b4aa1b587f.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <ul>
            <li class="@(ActiveSection == "Profile" ? "active" : "")" @onclick='() => SetSection("Profile")'>
                <span class="nav-icon">👤</span> Profile
            </li>
            <li class="@(ActiveSection == "Notifications" ? "active" : "")" @onclick='() => SetSection("Notifications")'>
                <span class="nav-icon">🔔</span> Notifications
            </li>
            <li class="@(ActiveSection == "Security" ? "active" : "")" @onclick='() => SetSection("Security")'>
                <span class="nav-icon">🔒</span> Security
            </li>
            <li class="@(ActiveSection == "Appearance" ? "active" : "")" @onclick='() => SetSection("Appearance")'>
                <span class="nav-icon">🎨</span> Appearance
            </li>
        </ul>
    </nav>

    <main class="settings-content">
        @if (!string.IsNullOrEmpty(ToastMessage))
        {
            <div class="toast @ToastType">
                @ToastMessage
                <button class="toast-close" @onclick="DismissToast">✕</button>
            </div>
        }

        @if (ActiveSection == "Profile")
        {
            <section class="settings-section">
                <h2>Profile Settings</h2>
                @if (_profile != null)
                {
                    <div class="avatar-preview">
                        <img src="@_editProfile.AvatarUrl" alt="Avatar" class="avatar-img" />
                        <p class="avatar-url">@_editProfile.AvatarUrl</p>
                    </div>
                    <div class="form-group">
                        <label for="displayName">Display Name</label>
                        <input id="displayName" type="text" @bind="_editProfile.DisplayName" />
                    </div>
                    <div class="form-group">
                        <label for="email">Email</label>
                        <input id="email" type="email" @bind="_editProfile.Email" />
                    </div>
                    <div class="form-group">
                        <label for="bio">Bio</label>
                        <textarea id="bio" rows="4" @bind="_editProfile.Bio"></textarea>
                    </div>
                    <div class="form-group">
                        <label for="avatarUrl">Avatar URL</label>
                        <input id="avatarUrl" type="text" @bind="_editProfile.AvatarUrl" />
                    </div>
                    <div class="button-group">
                        <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                        <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                    </div>
                }
            </section>
        }
        else if (ActiveSection == "Notifications")
        {
            <section class="settings-section">
                <h2>Notification Preferences</h2>
                @if (_notificationPrefs != null)
                {
                    <div class="toggle-group">
                        <label class="toggle-label">
                            <input type="checkbox" @bind="_editEmailNotifications" />
                            <span class="toggle-switch"></span>
                            Email Notifications
                        </label>
                    </div>
                    <div class="toggle-group">
                        <label class="toggle-label">
                            <input type="checkbox" @bind="_editPushNotifications" />
                            <span class="toggle-switch"></span>
                            Push Notifications
                        </label>
                    </div>
                    <div class="toggle-group">
                        <label class="toggle-label">
                            <input type="checkbox" @bind="_editWeeklyDigest" />
                            <span class="toggle-switch"></span>
                            Weekly Digest
                        </label>
                    </div>

                    <h3>Muted Channels</h3>
                    <div class="channels-list">
                        @foreach (var channel in _allChannels)
                        {
                            <label class="channel-item">
                                <input type="checkbox" checked="@_editMutedChannels.Contains(channel)"
                                       @onchange="(e) => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                                @channel
                            </label>
                        }
                    </div>
                    <div class="button-group">
                        <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
                    </div>
                }
            </section>
        }
        else if (ActiveSection == "Security")
        {
            <section class="settings-section">
                <h2>Security Settings</h2>
                @if (_securitySettings != null)
                {
                    <div class="expandable-panel">
                        <button class="panel-header" @onclick="TogglePasswordPanel">
                            <span>Change Password</span>
                            <span class="expand-icon">@(_showPasswordPanel ? "▼" : "▶")</span>
                        </button>
                        @if (_showPasswordPanel)
                        {
                            <div class="panel-body">
                                <div class="form-group">
                                    <label for="currentPassword">Current Password</label>
                                    <input id="currentPassword" type="password" @bind="_currentPassword" />
                                </div>
                                <div class="form-group">
                                    <label for="newPassword">New Password</label>
                                    <input id="newPassword" type="password" @bind="_newPassword" />
                                </div>
                                <div class="form-group">
                                    <label for="confirmPassword">Confirm Password</label>
                                    <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                                </div>
                                <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                            </div>
                        }
                    </div>

                    <div class="toggle-group security-toggle">
                        <label class="toggle-label">
                            <input type="checkbox" @bind="_editTwoFactor" />
                            <span class="toggle-switch"></span>
                            Two-Factor Authentication
                        </label>
                        <span class="status-indicator @(_editTwoFactor ? "enabled" : "disabled")">
                            @(_editTwoFactor ? "Enabled" : "Disabled")
                        </span>
                    </div>

                    <h3>Active Sessions</h3>
                    <div class="sessions-table-container">
                        <table class="sessions-table">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th>Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _securitySettings.Sessions)
                                {
                                    <tr>
                                        <td>@session.Device</td>
                                        <td>@session.Location</td>
                                        <td>@FormatLastActive(session.LastActive)</td>
                                        <td>
                                            @if (session.Id != _currentSessionId)
                                            {
                                                <button class="btn btn-danger btn-sm" @onclick="() => ConfirmRevokeSession(session)">
                                                    Revoke
                                                </button>
                                            }
                                            else
                                            {
                                                <span class="current-badge">Current</span>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>

                    @if (_showRevokeConfirm)
                    {
                        <div class="modal-overlay" @onclick="CancelRevoke">
                            <div class="modal" @onclick:stopPropagation="true">
                                <h3>Revoke Session</h3>
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?</p>
                                <div class="button-group">
                                    <button class="btn btn-danger" @onclick="RevokeSession">Revoke</button>
                                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                </div>
                            </div>
                        </div>
                    }
                }
            </section>
        }
        else if (ActiveSection == "Appearance")
        {
            <section class="settings-section">
                <h2>Appearance Settings</h2>
                @if (_appearance != null)
                {
                    <div class="form-group">
                        <label>Theme</label>
                        <div class="radio-group">
                            <label class="radio-label">
                                <input type="radio" name="theme" value="Light" checked="@(_editTheme == "Light")" @onchange='() => _editTheme = "Light"' /> Light
                            </label>
                            <label class="radio-label">
                                <input type="radio" name="theme" value="Dark" checked="@(_editTheme == "Dark")" @onchange='() => _editTheme = "Dark"' /> Dark
                            </label>
                            <label class="radio-label">
                                <input type="radio" name="theme" value="System" checked="@(_editTheme == "System")" @onchange='() => _editTheme = "System"' /> System
                            </label>
                        </div>
                    </div>

                    <div class="form-group">
                        <label>Font Size</label>
                        <div class="radio-group">
                            <label class="radio-label">
                                <input type="radio" name="fontSize" value="Small" checked="@(_editFontSize == "Small")" @onchange='() => _editFontSize = "Small"' /> Small
                            </label>
                            <label class="radio-label">
                                <input type="radio" name="fontSize" value="Medium" checked="@(_editFontSize == "Medium")" @onchange='() => _editFontSize = "Medium"' /> Medium
                            </label>
                            <label class="radio-label">
                                <input type="radio" name="fontSize" value="Large" checked="@(_editFontSize == "Large")" @onchange='() => _editFontSize = "Large"' /> Large
                            </label>
                        </div>
                    </div>

                    <div class="form-group">
                        <label for="language">Language</label>
                        <select id="language" @bind="_editLanguage">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>

                    <div class="toggle-group">
                        <label class="toggle-label">
                            <input type="checkbox" @bind="_editCompactMode" />
                            <span class="toggle-switch"></span>
                            Compact Mode
                        </label>
                    </div>

                    <h3>Live Preview</h3>
                    <div class="live-preview @GetPreviewClasses()">
                        <div class="preview-header">Preview Header</div>
                        <div class="preview-body">
                            <p>This is a preview of your selected appearance settings.</p>
                            <p>Theme: @_editTheme | Font: @_editFontSize | Language: @_editLanguage</p>
                            <button class="preview-btn">Sample Button</button>
                        </div>
                    </div>

                    <div class="button-group">
                        <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
                    </div>
                }
            </section>
        }
    </main>
</div>

@code {
    private string ActiveSection { get; set; } = "Profile";
    private string? ToastMessage { get; set; }
    private string ToastType { get; set; } = "success";

    // Profile
    private UserProfile? _profile;
    private ProfileEdit _editProfile = new();

    // Notifications
    private NotificationPrefs? _notificationPrefs;
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _editMutedChannels = new();
    private readonly List<string> _allChannels = new() { "general", "marketing", "engineering", "design", "announcements" };

    // Security
    private SecuritySettings? _securitySettings;
    private bool _showPasswordPanel;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _editTwoFactor;
    private string _currentSessionId = "session-1";
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private AppearanceSettings? _appearance;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
        await LoadNotifications();
        await LoadSecurity();
        await LoadAppearance();
    }

    private void SetSection(string section)
    {
        ActiveSection = section;
        DismissToast();
    }

    // Profile methods
    private async Task LoadProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
        ResetProfileEdit();
    }

    private void ResetProfileEdit()
    {
        if (_profile == null) return;
        _editProfile = new ProfileEdit
        {
            DisplayName = _profile.DisplayName,
            Email = _profile.Email,
            AvatarUrl = _profile.AvatarUrl,
            Bio = _profile.Bio
        };
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editProfile.DisplayName, _editProfile.Email, _editProfile.AvatarUrl, _editProfile.Bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileEdit();
        ShowToast("Changes discarded.", "info");
    }

    // Notification methods
    private async Task LoadNotifications()
    {
        _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
        _editEmailNotifications = _notificationPrefs.EmailNotifications;
        _editPushNotifications = _notificationPrefs.PushNotifications;
        _editWeeklyDigest = _notificationPrefs.WeeklyDigest;
        _editMutedChannels = new List<string>(_notificationPrefs.MutedChannels);
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_editMutedChannels.Contains(channel))
            _editMutedChannels.Add(channel);
        else if (!muted)
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, new List<string>(_editMutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
        ShowToast("Notification preferences saved!", "success");
    }

    // Security methods
    private async Task LoadSecurity()
    {
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _editTwoFactor = _securitySettings.TwoFactorEnabled;
    }

    private void TogglePasswordPanel() => _showPasswordPanel = !_showPasswordPanel;

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _showPasswordPanel = false;
        await LoadSecurity();
        ShowToast("Password updated successfully!", "success");
    }

    private void ConfirmRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
        _showRevokeConfirm = false;
    }

    private async Task RevokeSession()
    {
        if (_sessionToRevoke != null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadSecurity();
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.", "success");
        }
        CancelRevoke();
    }

    private string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }

    // Appearance methods
    private async Task LoadAppearance()
    {
        _appearance = await SettingsService.GetAppearanceAsync();
        _editTheme = _appearance.Theme;
        _editFontSize = _appearance.FontSize;
        _editLanguage = _appearance.Language;
        _editCompactMode = _appearance.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-{_editTheme.ToLower()} preview-font-{_editFontSize.ToLower()}";
        if (_editCompactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast
    private void ShowToast(string message, string type)
