+    {
+        var classes = $"preview-{_editTheme.ToLower()} preview-font-{_editFontSize.ToLower()}";
+        if (_editCompactMode) classes += " preview-compact";
+        return classes;
+    }
+
+    private async Task SaveAppearance()
+    {
+        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
+        await SettingsService.SaveAppearanceAsync(settings);
+        _appearance = settings;
+        ShowToast("Appearance settings saved!", "success");
+    }
